"""
modules/genai_financial_copilot.py — ProQuant Capital | Generative AI RAG Copilot v11.0
========================================================================================
Retrieval-Augmented Generation (RAG) simülasyonu ile binlerce SEC (10-K, 10-Q) raporunu 
okuyup vektörel benzerlik (Cosine Similarity) arayan LLM analiz motoru.
Author: ProQuant Capital AI Hub | Version: 11.0.0
"""
class GenAIFinancialCopilot:
    def calculate_cosine_similarity(self, v1: list, v2: list) -> float:
        """İki vektör arasındaki sözde benzerliği hesaplar."""
        dot = sum(a*b for a, b in zip(v1, v2))
        norm1 = sum(a*a for a in v1) ** 0.5
        norm2 = sum(b*b for b in v2) ** 0.5
        if norm1 * norm2 == 0: return 0.0
        return dot / (norm1 * norm2)

